export function nextGeneration(grid: boolean[][]): boolean[][] {
  if (grid.length === 0) return [];

  const rows = grid.length;
  const cols = grid[0].length;

  const countNeighbors = (r: number, c: number): number => {
    let count = 0;
    for (let dr = -1; dr <= 1; dr++) {
      for (let dc = -1; dc <= 1; dc++) {
        if (dr === 0 && dc === 0) continue;
        const nr = r + dr;
        const nc = c + dc;
        if (nr >= 0 && nr < rows && nc >= 0 && nc < cols && grid[nr][nc]) {
          count++;
        }
      }
    }
    return count;
  };

  const next: boolean[][] = [];
  for (let r = 0; r < rows; r++) {
    const row: boolean[] = [];
    for (let c = 0; c < cols; c++) {
      const neighbors = countNeighbors(r, c);
      const alive = grid[r][c];
      row.push(alive ? neighbors === 2 || neighbors === 3 : neighbors === 3);
    }
    next.push(row);
  }

  // Trim dead border rows
  let minRow = rows, maxRow = -1, minCol = cols, maxCol = -1;
  for (let r = 0; r < rows; r++) {
    for (let c = 0; c < cols; c++) {
      if (next[r][c]) {
        if (r < minRow) minRow = r;
        if (r > maxRow) maxRow = r;
        if (c < minCol) minCol = c;
        if (c > maxCol) maxCol = c;
      }
    }
  }

  if (maxRow === -1) return [];

  const result: boolean[][] = [];
  for (let r = minRow; r <= maxRow; r++) {
    result.push(next[r].slice(minCol, maxCol + 1));
  }
  return result;
}
